import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';
import './Login.css'; // Importer les styles personnalisés
import sImage from '../pages/1.png';

function Login() {
  const [loginInfo, setLoginInfo] = useState({ email: '', password: '' });
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setLoginInfo((prev) => ({ ...prev, [name]: value }));
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    const { email, password } = loginInfo;
    if (!email || !password) return handleError('Email and password are required');

    try {
      const response = await fetch('http://localhost:5001/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginInfo),
      });
      const result = await response.json();
      const { success, message, jwtToken, name, error } = result;

      if (success) {
        handleSuccess(message);
        localStorage.setItem('token', jwtToken);
        localStorage.setItem('loggedInUser', name);
        setTimeout(() => navigate('/home'), 1000);
      } else {
        handleError(error?.details?.[0]?.message || message);
      }
    } catch (err) {
      handleError(err.message);
    }
  };

  return (
    <div className="login-container">
      <div className="login-box">
        <div className="login-image">
          <img src="1.png" alt="Food" />
        </div>
        <div className="login-form">
          <h2>Login to Account</h2>
          <p>Please enter your email and password to continue</p>
          <form onSubmit={handleLogin}>
            <div className="form-group">
              <label>Email Address</label>
              <input type="email" name="email" placeholder="Email Address" value={loginInfo.email} onChange={handleChange} className="form-control" />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" name="password" placeholder="Password" value={loginInfo.password} onChange={handleChange} className="form-control" />
            </div>
            <div className="form-check">
              <input type="checkbox" className="form-check-input" id="remember" />
              <label className="form-check-label" htmlFor="remember">Remember Password</label>
            </div>
            <p className="forgot-password"><Link to="/forgot-password">Forgot Password?</Link></p>
            <button type="submit" className="btn btn-primary login-btn">Sign In</button>
            <p className="create-account">Don't have an account? <Link to="/signup">Create Account</Link></p>
          </form>
        </div>
      </div>
      <ToastContainer />
    </div>
  );
}

export default Login;
